// Java 26 - PEM encoding of crypto objects (JEP 524 PREVIEW)
// Learn: encode and decode keys as PEM text.
PublicKey publicKey = KeyPairGenerator.getInstance("EC").generateKeyPair().getPublic();
PEMEncoder encoder = PEMEncoder.of();
// PEM text is portable key encoding.
String pem = encoder.encodeToString(publicKey);
PEMDecoder decoder = PEMDecoder.of();
PublicKey restored = decoder.decode(pem, PublicKey.class);
System.out.println(restored.getAlgorithm());
